package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
)

type Order struct {
	ID        int    `json:"id"`
	Customer  string `json:"customer"`
	Product   string `json:"product"`
	Quantity  int    `json:"quantity"`
	Price     float64 `json:"price"`
}

func getOrder(w http.ResponseWriter, r *http.Request) {
	// Extract the order ID from the URL path
	vars := mux.Vars(r)
	orderID, err := strconv.Atoi(vars["id"])
	if err != nil {
		http.Error(w, "Invalid order ID", http.StatusBadRequest)
		return
	}

	// Query the database for the order details
	db, err := sql.Open("mysql", "user:password@tcp(localhost:3306)/orders")
	if err != nil {
		http.Error(w, "Failed to connect to database", http.StatusInternalServerError)
		return
	}
	defer db.Close()

	var order Order
	err = db.QueryRow("SELECT * FROM orders WHERE id=?", orderID).Scan(&order.ID, &order.Customer, &order.Product, &order.Quantity, &order.Price)
	if err != nil {
		http.Error(w, "Failed to query database", http.StatusInternalServerError)
		return
	}

	// Marshal the order details into JSON format
	jsonOrder, err := json.Marshal(order)
	if err != nil {
		http.Error(w, "Failed to marshal order details", http.StatusInternalServerError)
		return
	}

	// Send the JSON response back to the client
	w.Header().Set("Content-Type", "application/json")
	w.Write(jsonOrder)
}